        ("sub-2001_T1w_pial.L.surf.gii", "pial", "L.surf.gii"),
        ("sub-2001_T1w_pial.R.surf.gii", "pial", "R.surf.gii"),
        ("sub-2001_T1w_smoothwm.R.surf.gii", "smoothwm", "R.surf.gii"),
    ];

    for (filename, expected_suffix, expected_ext) in cases {
        let result = parse_bids_filename(filename).unwrap();
        assert_eq!(result.entities.get("sub"), Some(&"2001".to_string()));
        assert_eq!(result.suffix, expected_suffix);
        assert_eq!(result.extension, expected_ext);
    }
}

#[test]
fn test_parse_transform_files() {
    // Test transformation files (.h5, .txt)
    let cases = vec![
        ("sub-2001_T1w_target-fsnative_affine.txt", "affine", "txt"),
        ("sub-2001_T1w_target-MNI152NLin2009cAsym_warp.h5", "warp", "h5"),
        ("sub-2001_T1w_space-MNI152NLin2009cAsym_target-T1w_warp.h5", "warp", "h5"),
        ("sub-2001_T1w_space-orig_target-T1w_affine.txt", "affine", "txt"),
    ];

    for (filename, expected_suffix, expected_ext) in cases {
        let result = parse_bids_filename(filename).unwrap();
        assert_eq!(result.entities.get("sub"), Some(&"2001".to_string()));
        assert_eq!(result.suffix, expected_suffix);
        assert_eq!(result.extension, expected_ext);

        // Check specific entities
        if filename.contains("target-") {
            assert!(result.entities.contains_key("target"));
        }
        if filename.contains("space-") {
            assert!(result.entities.contains_key("space"));
        }
    }
}

#[test]
fn test_parse_tissue_probability_maps() {
    // Test tissue class files
    let classes = vec!["CSF", "GM", "WM"];

    for class in classes {
        let filename = format!("sub-2001_T1w_class-{}_probtissue.nii.gz", class);
        let result = parse_bids_filename(&filename).unwrap();

        assert_eq!(result.entities.get("sub"), Some(&"2001".to_string()));
        assert_eq!(result.entities.get("class"), Some(&class.to_string()));
        assert_eq!(result.suffix, "probtissue");
        assert_eq!(result.extension, "nii.gz");
    }

    // Test dtissue file
    let result = parse_bids_filename("sub-2001_T1w_dtissue.nii.gz").unwrap();
    assert_eq!(result.suffix, "dtissue");
}

#[test]
fn test_parse_roi_labels() {
    // Test label ROI files
    let labels = vec!["aparcaseg", "aseg"];

    for label in labels {
        let filename = format!("sub-2001_T1w_label-{}_roi.nii.gz", label);
