use bids_rust::{BidsProject, SearchBuilder};
use std::fs;
use tempfile::TempDir;

fn create_test_bids_project() -> (TempDir, BidsProject) {
    let temp_dir = TempDir::new().unwrap();
    let root_path = temp_dir.path();

    // Create dataset_description.json
    let dataset_desc = r#"{
        "Name": "Search Test Dataset",
        "BIDSVersion": "1.6.0"
    }"#;
    fs::write(root_path.join("dataset_description.json"), dataset_desc).unwrap();

    // Create directory structure
    fs::create_dir_all(root_path.join("sub-01/ses-01/func")).unwrap();
    fs::create_dir_all(root_path.join("sub-01/ses-01/anat")).unwrap();
    fs::create_dir_all(root_path.join("sub-01/ses-02/func")).unwrap();
    fs::create_dir_all(root_path.join("sub-02/ses-01/func")).unwrap();
    fs::create_dir_all(root_path.join("sub-02/ses-02/func")).unwrap();
    fs::create_dir_all(root_path.join("derivatives/fmriprep/sub-01/ses-01/func")).unwrap();

    // Create functional files
    fs::write(
        root_path.join("sub-01/ses-01/func/sub-01_ses-01_task-rest_bold.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("sub-01/ses-01/func/sub-01_ses-01_task-rest_bold.json"),
        r#"{"RepetitionTime": 2.0}"#
    ).unwrap();
    fs::write(
        root_path.join("sub-01/ses-01/func/sub-01_ses-01_task-rest_events.tsv"),
        "onset\tduration\ttrial_type\n0\t2\tstim\n"
    ).unwrap();
    fs::write(
        root_path.join("sub-01/ses-02/func/sub-01_ses-02_task-nback_run-1_bold.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("sub-01/ses-02/func/sub-01_ses-02_task-nback_run-2_bold.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("sub-02/ses-01/func/sub-02_ses-01_task-rest_bold.nii.gz"),
        b"dummy"
    ).unwrap();

    // Create anatomical files
    fs::write(
        root_path.join("sub-01/ses-01/anat/sub-01_ses-01_T1w.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("sub-01/ses-01/anat/sub-01_ses-01_T2w.nii.gz"),
        b"dummy"
    ).unwrap();

    // Create derivatives
    fs::write(
        root_path.join("derivatives/fmriprep/sub-01/ses-01/func/sub-01_ses-01_task-rest_space-MNI152NLin2009cAsym_desc-preproc_bold.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("derivatives/fmriprep/sub-01/ses-01/func/sub-01_ses-01_task-rest_desc-confounds_timeseries.tsv"),
        "trans_x\ttrans_y\ttrans_z\n0.1\t0.2\t0.3\n"
    ).unwrap();

    let project = BidsProject::new(root_path).unwrap();
    (temp_dir, project)
}

#[test]
fn test_search_all_files() {
    let (_temp_dir, project) = create_test_bids_project();

    let files = project.search_files()
        .execute()
        .unwrap();

    // Should find all BIDS files
    assert!(files.len() > 0);
}

#[test]
fn test_search_by_subject() {
    let (_temp_dir, project) = create_test_bids_project();

    let files = project.search_files()
        .subject("01")
