/// Test the subject-specific interface that provides organized access to data
#[test]
fn test_subject_interface_basic() -> Result<()> {
    // Create a dataset with subject data across modalities
    let temp_dir = MockBidsBuilder::new("subject_interface_test")
        .add_participant(Participant {
            id: "sub-01".to_string(),
            age: Some(25),
            sex: Some("M".to_string()),
            handedness: Some("R".to_string()),
        })
        .add_files(vec![
            // Anatomical
            FileSpec {
                subject: "01".to_string(),
                session: None,
                datatype: "anat".to_string(),
                task: None,
                run: None,
                suffix: "T1w".to_string(),
                extension: "nii.gz".to_string(),
                space: None,
                desc: None,
                is_derivative: false,
            },
            // Functional
            FileSpec {
                subject: "01".to_string(),
                session: None,
                datatype: "func".to_string(),
                task: Some("rest".to_string()),
                run: Some("01".to_string()),
                suffix: "bold".to_string(),
                extension: "nii.gz".to_string(),
                space: None,
                desc: None,
                is_derivative: false,
            },
            // Preprocessed functional
            FileSpec {
                subject: "01".to_string(),
                session: None,
                datatype: "func".to_string(),
                task: Some("rest".to_string()),
                run: Some("01".to_string()),
                suffix: "bold".to_string(),
                extension: "nii.gz".to_string(),
                space: Some("MNI152NLin2009cAsym".to_string()),
                desc: Some("preproc".to_string()),
                is_derivative: true,
            },
            // Brain mask
            FileSpec {
                subject: "01".to_string(),
                session: None,
                datatype: "anat".to_string(),
                task: None,
                run: None,
                suffix: "mask".to_string(),
                extension: "nii.gz".to_string(),
                space: Some("MNI152NLin2009cAsym".to_string()),
                desc: Some("brain".to_string()),
                is_derivative: true,
            },
        ])
        .add_events(
            FileSpec {
                subject: "01".to_string(),
                session: None,
                datatype: "func".to_string(),
                task: Some("rest".to_string()),
                run: Some("01".to_string()),
                suffix: "events".to_string(),
                extension: "tsv".to_string(),
                space: None,
                desc: None,
                is_derivative: false,
            },
            EventData {
                onset: vec![0.0, 60.0, 120.0],
                duration: vec![30.0, 30.0, 30.0],
                trial_type: vec!["rest".to_string(), "task".to_string(), "rest".to_string()],
            },
        )
        .add_confounds(
            FileSpec {
                subject: "01".to_string(),
                session: None,
                datatype: "func".to_string(),
                task: Some("rest".to_string()),
                run: Some("01".to_string()),
                suffix: "timeseries".to_string(),
                extension: "tsv".to_string(),
                space: None,
                desc: Some("confounds".to_string()),
                is_derivative: true,
            },
            ConfoundData {
                framewise_displacement: vec![0.1; 150],
                trans_x: vec![0.0; 150],
                trans_y: vec![0.0; 150],
                trans_z: vec![0.0; 150],
                rot_x: vec![0.0; 150],
                rot_y: vec![0.0; 150],
                rot_z: vec![0.0; 150],
                csf: vec![100.0; 150],
                white_matter: vec![150.0; 150],
            },
        )
        .build()?;

    let project = BidsProject::new(temp_dir.path())?;

    // Get subject-specific interface
    let subject = project.subject("01")?;

    // Test that interface provides access to different data types

    // 1. Anatomical scans
    let anat_scans = subject.anatomical_scans()?;
    assert_eq!(anat_scans.len(), 1, "Should have one anatomical scan");
    assert_eq!(anat_scans[0].suffix, "T1w");

    // 2. Functional scans
    let func_scans = subject.functional_scans()?;
    assert_eq!(func_scans.len(), 1, "Should have one functional scan");
    assert_eq!(func_scans[0].suffix, "bold");
    assert_eq!(func_scans[0].entities.get("task"), Some(&"rest".to_string()));

    // 3. Events
    let events = subject.events()?;
    assert_eq!(events.len(), 1, "Should have one event file");
    assert_eq!(events[0].data.len(), 3, "Should have 3 events");

    // 4. Preprocessed scans (derivatives)
    let preproc_scans = subject.preprocessed_scans()?;
    assert_eq!(preproc_scans.len(), 1, "Should have one preprocessed scan");
    assert!(preproc_scans[0].entities.contains_key("space"));
    assert!(preproc_scans[0].entities.contains_key("desc"));

    // 5. Confounds
    let confounds = subject.confounds()?;
    assert_eq!(confounds.len(), 1, "Should have one confound file");
    assert_eq!(confounds[0].n_timepoints, 150);

    // 6. Brain mask
    let masks = subject.brain_masks()?;
    assert_eq!(masks.len(), 1, "Should have one brain mask");
    assert_eq!(masks[0].suffix, "mask");

    Ok(())
}

