#[test]
fn test_confound_pca_processing() -> Result<()> {
    let temp_dir = create_bids_with_derivatives()?;
    let project = BidsProject::new(temp_dir.path())?;

    // Read confounds with PCA
    let confounds = project.read_confounds()
        .columns(&["trans_x", "trans_y", "trans_z", "rot_x", "rot_y", "rot_z"])
        .with_pca(3) // Reduce to 3 components
        .collect()?;

    assert_eq!(confounds.len(), 1);
    let confound = &confounds[0];

    // Should have PCA results
    assert!(confound.pca_result.is_some());

    let pca = confound.pca_result.as_ref().unwrap();
    assert_eq!(pca.n_components, 3);
    assert_eq!(pca.components.nrows(), 3);
    assert_eq!(pca.components.ncols(), 6); // 6 input columns

    // Check explained variance
    assert!(pca.explained_variance_ratio.iter().sum::<f64>() <= 1.0);

    Ok(())
}

