   275→    /// Get the full file path for a FileSpec
   276→    fn get_file_path(&self, root_path: &Path, file_spec: &FileSpec) -> PathBuf {
   277→        let mut path = PathBuf::from(root_path);
   278→
   279→        // Add derivatives path if needed
   280→        if file_spec.is_derivative {
   281→            path.push("derivatives");
   282→            path.push("fmriprep");
   283→        }
   284→
   285→        // Add subject directory
   286→        let sub_dir = if file_spec.subject.starts_with("sub-") {
   287→            file_spec.subject.clone()
   288→        } else {
   289→            format!("sub-{}", file_spec.subject)
   290→        };
   291→        path.push(&sub_dir);
   292→
   293→        // Add session directory if present
   294→        if let Some(ses) = &file_spec.session {
   295→            let ses_dir = if ses.starts_with("ses-") {
   296→                ses.clone()
   297→            } else {
   298→                format!("ses-{}", ses)
   299→            };
   300→            path.push(&ses_dir);
   301→        }
   302→
   303→        // Add datatype directory
   304→        path.push(&file_spec.datatype);
   305→
   306→        // Build filename
   307→        let filename = self.build_filename(file_spec);
   308→        path.push(filename);
   309→
   310→        path
   311→    }
