   313→    /// Build BIDS filename from FileSpec
   314→    fn build_filename(&self, file_spec: &FileSpec) -> String {
   315→        let mut parts = Vec::new();
   316→
   317→        // Subject
   318→        if file_spec.subject.starts_with("sub-") {
   319→            parts.push(file_spec.subject.clone());
   320→        } else {
   321→            parts.push(format!("sub-{}", file_spec.subject));
   322→        }
   323→
   324→        // Session
   325→        if let Some(ses) = &file_spec.session {
   326→            if ses.starts_with("ses-") {
   327→                parts.push(ses.clone());
   328→            } else {
   329→                parts.push(format!("ses-{}", ses));
   330→            }
   331→        }
   332→
   333→        // Task
   334→        if let Some(task) = &file_spec.task {
   335→            parts.push(format!("task-{}", task));
   336→        }
   337→
   338→        // Run
   339→        if let Some(run) = &file_spec.run {
   340→            parts.push(format!("run-{}", run));
   341→        }
   342→
   343→        // Space (derivatives)
   344→        if let Some(space) = &file_spec.space {
   345→            parts.push(format!("space-{}", space));
   346→        }
   347→
   348→        // Description (derivatives)
   349→        if let Some(desc) = &file_spec.desc {
   350→            parts.push(format!("desc-{}", desc));
   351→        }
   352→
   353→        // Join parts with underscores and add suffix/extension
   354→        let base = parts.join("_");
   355→        format!("{}_{}.{}", base, file_spec.suffix, file_spec.extension)
   356→    }
   357→
   358→    /// Create JSON sidecar content
   359→    fn create_json_sidecar(&self, file_spec: &FileSpec) -> serde_json::Value {
   360→        match file_spec.suffix.as_str() {
   361→            "bold" => json!({
   362→                "TaskName": file_spec.task.as_deref().unwrap_or("rest"),
   363→                "RepetitionTime": 2.0,
   364→                "EchoTime": 0.03,
