/// Test sidecar JSON reading
#[test]
fn test_sidecar_reading() {
    // Use the common mock builder to create a dataset
    let temp_dir = common::mock_bids::create_simple_bids_dataset()
        .expect("Failed to create mock BIDS dataset");

    let project = BidsProject::new(temp_dir.path()).expect("Failed to create BIDS project");

    // Find JSON sidecar files
    let json_files = project.search_files()
        .extension("json")
        .execute()
        .expect("Failed to search for JSON files");

    assert!(json_files.len() > 0, "No JSON files found");

    // Read sidecar data
    let sidecars = project.read_sidecars().expect("Failed to read sidecars");

    assert!(sidecars.len() > 0, "No sidecars read");
    for sidecar in &sidecars {
        assert!(!sidecar.data.is_empty(), "Empty sidecar data");

        // Check for expected fields based on file type
        if sidecar.suffix == "bold" {
            assert!(sidecar.data.contains_key("TaskName"), "Missing TaskName in bold sidecar");
            assert!(sidecar.data.contains_key("RepetitionTime"), "Missing RepetitionTime in bold sidecar");
        } else if sidecar.suffix == "T1w" {
            assert!(sidecar.data.contains_key("MagneticFieldStrength"), "Missing MagneticFieldStrength in T1w sidecar");
        }
    }
}

