// ============================================================================

#[test]
fn test_search_with_custom_entities() {
    // R equivalent: custom entity search in bidser
    let temp_dir = TempDir::new().unwrap();
    let root = temp_dir.path();

    fs::create_dir_all(root.join("sub-01/func")).unwrap();
    fs::write(root.join("dataset_description.json"), r#"{"Name": "Test", "BIDSVersion": "1.6.0"}"#).unwrap();

    // Files with custom entities
    fs::write(root.join("sub-01/func/sub-01_task-rest_acq-mb4_bold.nii.gz"), b"").unwrap();
    fs::write(root.join("sub-01/func/sub-01_task-rest_acq-mb6_bold.nii.gz"), b"").unwrap();

    let project = BidsProject::new(root).unwrap();

    // Search by acquisition parameter
    let files = SearchBuilder::new(&project)
        .custom("acq", "mb4")
        .collect();

    assert_eq!(files.len(), 1);
    assert_eq!(files[0].get_entity("acq"), Some("mb4"));
}

#[test]
fn test_search_with_regex_patterns() {
    // R equivalent: regex-based search in bidser
    let temp_dir = TempDir::new().unwrap();
    let root = temp_dir.path();

    fs::create_dir_all(root.join("sub-01/func")).unwrap();
    fs::create_dir_all(root.join("sub-02/func")).unwrap();
    fs::create_dir_all(root.join("sub-10/func")).unwrap();
    fs::write(root.join("dataset_description.json"), r#"{"Name": "Test", "BIDSVersion": "1.6.0"}"#).unwrap();

    // Create files for different subjects
    fs::write(root.join("sub-01/func/sub-01_task-rest_bold.nii.gz"), b"").unwrap();
    fs::write(root.join("sub-02/func/sub-02_task-rest_bold.nii.gz"), b"").unwrap();
    fs::write(root.join("sub-10/func/sub-10_task-rest_bold.nii.gz"), b"").unwrap();

    let project = BidsProject::new(root).unwrap();

    // Search for subjects 01-09 using regex
    let files = SearchBuilder::new(&project)
        .regex("sub", r"0[1-9]")
        .collect();

    assert_eq!(files.len(), 2);
}

