#[test]
fn test_multimodal_dataset() {
    // R equivalent: handling datasets with multiple modalities
    let temp_dir = TempDir::new().unwrap();
    let root = temp_dir.path();

    // Create multi-modal structure
    let modalities = vec!["anat", "func", "dwi", "fmap", "perf"];
    for modality in &modalities {
        fs::create_dir_all(root.join(format!("sub-01/{}", modality))).unwrap();
    }

    fs::write(root.join("dataset_description.json"), r#"{"Name": "Test", "BIDSVersion": "1.6.0"}"#).unwrap();

    // Create files for each modality
    fs::write(root.join("sub-01/anat/sub-01_T1w.nii.gz"), b"").unwrap();
    fs::write(root.join("sub-01/func/sub-01_task-rest_bold.nii.gz"), b"").unwrap();
    fs::write(root.join("sub-01/dwi/sub-01_dwi.nii.gz"), b"").unwrap();
    fs::write(root.join("sub-01/fmap/sub-01_magnitude1.nii.gz"), b"").unwrap();
    fs::write(root.join("sub-01/perf/sub-01_asl.nii.gz"), b"").unwrap();

    let project = BidsProject::new(root).unwrap();
    let all_files = SearchBuilder::new(&project).collect();

    // Verify all modalities are found
    assert!(all_files.iter().any(|f| f.path.contains("anat")));
    assert!(all_files.iter().any(|f| f.path.contains("func")));
    assert!(all_files.iter().any(|f| f.path.contains("dwi")));
    assert!(all_files.iter().any(|f| f.path.contains("fmap")));
    assert!(all_files.iter().any(|f| f.path.contains("perf")));
}

