/// Test confounds reading with PCA (replicating test_read_confounds.R)
#[test]
fn test_confounds_reading() {
    // Create a mock BIDS dataset with confounds
    let n_timepoints = 100;
    let confound_data = ConfoundData {
        framewise_displacement: (0..n_timepoints).map(|i| 0.01 + 0.001 * (i as f64)).collect(),
        trans_x: (0..n_timepoints).map(|i| 0.1 * (i as f64 * 0.1).sin()).collect(),
        trans_y: (0..n_timepoints).map(|i| 0.1 * (i as f64 * 0.1).cos()).collect(),
        trans_z: (0..n_timepoints).map(|i| 0.05 * (i as f64 * 0.1).sin()).collect(),
        rot_x: (0..n_timepoints).map(|i| 0.01 * (i as f64 * 0.1).cos()).collect(),
        rot_y: (0..n_timepoints).map(|i| 0.01 * (i as f64 * 0.1).sin()).collect(),
        rot_z: (0..n_timepoints).map(|i| 0.005 * (i as f64 * 0.1).cos()).collect(),
        csf: (0..n_timepoints).map(|i| 100.0 + 5.0 * (i as f64 * 0.1).sin()).collect(),
        white_matter: (0..n_timepoints).map(|i| 150.0 + 3.0 * (i as f64 * 0.1).cos()).collect(),
    };

    let temp_dir = MockBidsBuilder::new("confounds_test")
        .add_participant(Participant {
            id: "01".to_string(),
            age: Some(25),
            sex: Some("M".to_string()),
            handedness: Some("R".to_string()),
        })
        .add_files(vec![
            FileSpec {
                subject: "01".to_string(),
                session: None,
                datatype: "func".to_string(),
                task: Some("rest".to_string()),
                run: Some("01".to_string()),
                suffix: "bold".to_string(),
                extension: "nii.gz".to_string(),
                space: None,
                desc: None,
                is_derivative: false,
            },
            FileSpec {
                subject: "01".to_string(),
                session: None,
                datatype: "func".to_string(),
                task: Some("rest".to_string()),
                run: Some("01".to_string()),
                suffix: "timeseries".to_string(),
                extension: "tsv".to_string(),
                space: None,
                desc: Some("confounds".to_string()),
                is_derivative: true,
            },
        ])
        .add_confounds(
            FileSpec {
                subject: "01".to_string(),
                session: None,
                datatype: "func".to_string(),
                task: Some("rest".to_string()),
                run: Some("01".to_string()),
                suffix: "timeseries".to_string(),
                extension: "tsv".to_string(),
                space: None,
                desc: Some("confounds".to_string()),
                is_derivative: true,
            },
            confound_data.clone(),
        )
        .build()
        .expect("Failed to create mock BIDS dataset");

    let project = BidsProject::new(temp_dir.path()).expect("Failed to create BIDS project");

    // Test 1: Find confound files
    let confound_files = project.search_files()
        .entity("desc", "confounds")
        .suffix("timeseries")
        .extension("tsv")
        .execute()
        .expect("Failed to search for confound files");

    assert!(confound_files.len() > 0, "No confound files found");

    // Test 2: Read confounds
    let confounds = project.read_confounds().expect("Failed to read confounds");

    assert!(confounds.len() > 0, "No confounds read");
    for confound in &confounds {
        // Check that all expected columns exist
        assert!(confound.data.contains_key("framewise_displacement"), "Missing framewise_displacement");
        assert!(confound.data.contains_key("trans_x"), "Missing trans_x");
        assert!(confound.data.contains_key("trans_y"), "Missing trans_y");
        assert!(confound.data.contains_key("trans_z"), "Missing trans_z");
        assert!(confound.data.contains_key("rot_x"), "Missing rot_x");
        assert!(confound.data.contains_key("rot_y"), "Missing rot_y");
        assert!(confound.data.contains_key("rot_z"), "Missing rot_z");
        assert!(confound.data.contains_key("csf"), "Missing csf");
        assert!(confound.data.contains_key("white_matter"), "Missing white_matter");

        // Check data lengths
        let n_rows = confound.data.get("framewise_displacement").unwrap().len();
        assert_eq!(n_rows, n_timepoints, "Wrong number of timepoints");

        for (_, values) in &confound.data {
            assert_eq!(values.len(), n_rows, "Inconsistent column lengths");
        }
    }

    // Test 3: PCA reduction
    let confounds_pca = project.read_confounds_with_pca(2).expect("Failed to read confounds with PCA");

    assert!(confounds_pca.len() > 0, "No confounds read with PCA");
    for confound in &confounds_pca {
        // Should have PC1 and PC2
        assert!(confound.pca_components.is_some(), "No PCA components");
        let pca = confound.pca_components.as_ref().unwrap();
        assert_eq!(pca.n_components(), 2, "Wrong number of PCA components");
        assert_eq!(pca.component_matrix.nrows(), 2, "Wrong PCA component matrix rows");
        assert_eq!(pca.component_matrix.ncols(), 9, "Wrong PCA component matrix cols"); // 9 original columns
    }
}

/// Test strict mode search (replicating test_search_files.R strict tests)
#[test]
fn test_search_strict_mode() {
    let temp_dir = MockBidsBuilder::new("strict_test")
        .add_participant(Participant {
            id: "01".to_string(),
            age: Some(25),
            sex: Some("M".to_string()),
            handedness: Some("R".to_string()),
        })
        .add_files(vec![
            // T1w file (no task entity)
            FileSpec {
                subject: "01".to_string(),
                session: None,
                datatype: "anat".to_string(),
                task: None,
                run: None,
                suffix: "T1w".to_string(),
                extension: "nii.gz".to_string(),
                space: None,
                desc: None,
                is_derivative: false,
            },
            // Bold file (has task entity)
            FileSpec {
                subject: "01".to_string(),
                session: None,
                datatype: "func".to_string(),
                task: Some("rest".to_string()),
                run: None,
                suffix: "bold".to_string(),
                extension: "nii.gz".to_string(),
                space: None,
                desc: None,
                is_derivative: false,
            },
        ])
        .build()
        .expect("Failed to create mock BIDS dataset");

    let project = BidsProject::new(temp_dir.path()).expect("Failed to create BIDS project");

    // Test 1: Strict mode should fail when searching for T1w with task
    // (T1w files don't have task entity)
    let strict_search = project.search_files()
        .subject("01")
        .task("rest")
        .suffix("T1w")
        .strict(true)
        .execute();

    match strict_search {
        Ok(files) => assert_eq!(files.len(), 0, "Strict search should return no files"),
        Err(_) => {} // Also acceptable
    }

    // Test 2: Non-strict mode should find T1w even when searching with task
    let non_strict_search = project.search_files()
        .subject("01")
        .task("rest")
        .suffix("T1w")
        .strict(false)
        .execute()
        .expect("Non-strict search failed");

    assert_eq!(non_strict_search.len(), 1, "Non-strict search should find T1w file");
    assert_eq!(non_strict_search[0].suffix, "T1w");
}

