        .expect("Failed to create mock BIDS dataset");

    let project = BidsProject::new(temp_dir.path()).expect("Failed to create BIDS project");

    // Test 1: Filter by session
    let ses01_files = project.search_files()
        .session("01")
        .execute()
        .expect("Failed to search for session 01 files");

    assert_eq!(ses01_files.len(), 2, "Expected 2 files for session 01");
    for file in &ses01_files {
        assert_eq!(file.entities.get("ses"), Some(&"01".to_string()));
    }

    let ses02_files = project.search_files()
        .session("02")
        .execute()
        .expect("Failed to search for session 02 files");

    assert_eq!(ses02_files.len(), 1, "Expected 1 file for session 02");
    assert_eq!(ses02_files[0].entities.get("ses"), Some(&"02".to_string()));

    // Test 2: Combined subject and session filtering
    let sub01_ses01_files = project.search_files()
        .subject("01")
        .session("01")
        .execute()
        .expect("Failed to search for subject 01 session 01 files");

    assert_eq!(sub01_ses01_files.len(), 1, "Expected 1 file for subject 01 session 01");
    assert_eq!(sub01_ses01_files[0].entities.get("sub"), Some(&"01".to_string()));
    assert_eq!(sub01_ses01_files[0].entities.get("ses"), Some(&"01".to_string()));
}

