                Some("ses-02"),
                "derivatives/fmriprep/sub-01/ses-02/anat/sub-01_ses-02_space-MNI152NLin2009cAsym_desc-brain_mask.nii.gz",
                b"ses-02 mask"
            )
            .build()?;

        let project = BidsProject::open(&mock)?;

        // Test finding masks for specific session
        let masks = find_brain_masks(&project, Some("sub-01"), None)?;
        assert_eq!(masks.len(), 2);

        // Test mask creation with session
        let mask_result = create_brain_mask(&project, "sub-01", Some("ses-01"), 0.5);
        assert!(mask_result.is_ok());

        Ok(())
    }

    // Helper functions for brain mask operations
    fn validate_mask_threshold(threshold: f64) -> Result<()> {
        if threshold < 0.0 || threshold > 1.0 {
            return Err(BidsError::InvalidParameter(
                format!("Mask threshold must be between 0.0 and 1.0, got: {}", threshold)
            ));
        }

        if threshold.is_nan() || threshold.is_infinite() {
            return Err(BidsError::InvalidParameter(
                "Mask threshold must be a valid number".to_string()
            ));
        }

        Ok(())
    }

    fn create_brain_mask(
        project: &BidsProject,
        subject: &str,
        session: Option<&str>,
        threshold: f64,
    ) -> Result<PathBuf> {
        validate_mask_threshold(threshold)?;

        // Look for existing brain mask in derivatives
        let search_result = if let Some(ses) = session {
            project.search_files()
                .subject(subject)
                .session(ses)
                .suffix("mask")
                .desc("brain")
                .extension("nii.gz")
                .find()?
        } else {
            project.search_files()
                .subject(subject)
                .suffix("mask")
                .desc("brain")
                .extension("nii.gz")
                .find()?
        };

        if search_result.is_empty() {
            return Err(BidsError::FileNotFound(
                format!("No brain mask found for subject: {} session: {:?}", subject, session)
            ));
        }

        // In real implementation, would apply threshold to create new mask
        // For tests, just return the found mask path
        Ok(search_result[0].path.clone())
    }

    fn find_brain_masks(
        project: &BidsProject,
        subject: Option<&str>,
        space: Option<&str>,
    ) -> Result<Vec<PathBuf>> {
        let mut search = project.search_files()
            .suffix("mask")
            .desc("brain")
            .extension("nii.gz");

        if let Some(sub) = subject {
            search = search.subject(sub);
        }

        if let Some(sp) = space {
            search = search.space(sp);
        }

        let files = search.find()?;
        Ok(files.into_iter().map(|f| f.path).collect())
    }
}

