/// * None pattern returns default
/// * Empty pattern returns default
pub fn key_match(pattern: Option<&str>, value: &str, default: bool) -> bool {
    match pattern {
        None => default,
        Some(".*") => true, // Wildcard matches everything
        Some(p) => {
            if p.is_empty() {
                default
            } else {
                Regex::new(p)
                    .map(|re| re.is_match(value))
                    .unwrap_or(false)
            }
        }
    }
}

/// Generate BIDS-compliant path for subject data
///
/// # Arguments
/// * `subject` - Subject identifier (e.g., "sub-01")
/// * `session` - Optional session identifier (e.g., "ses-01")
/// * `modality` - Data modality (e.g., "anat", "func", "fmap")
/// * `derivatives` - Whether this is a derivatives path
///
/// # Returns
/// BIDS-compliant path string
pub fn generate_bids_path(
    subject: &str,
    session: Option<&str>,
    modality: &str,
    derivatives: bool,
) -> String {
    let mut path_parts = Vec::new();

    if derivatives {
        path_parts.push("derivatives");
    }

    path_parts.push(subject);

    if let Some(ses) = session {
        path_parts.push(ses);
    }

    path_parts.push(modality);

    path_parts.join("/")
}

/// Reconstruct path from tree node components
///
/// # Arguments
/// * `nodes` - Vector of path components
/// * `derivatives` - Whether to prepend derivatives directory
///
/// # Returns
/// Reconstructed path string
pub fn reconstruct_node_path(nodes: &[&str], derivatives: bool) -> String {
    if derivatives && !nodes.is_empty() {
        let mut path = vec!["derivatives"];
        path.extend_from_slice(nodes);
        path.join("/")
    } else {
        nodes.join("/")
    }
}

/// Valid BIDS entity names
static VALID_ENTITIES: Lazy<Vec<&'static str>> = Lazy::new(|| {
    vec![
        "sub", "ses", "task", "acq", "ce", "rec", "dir", "run", 
        "mod", "echo", "flip", "inv", "mt", "part", "recording",
        "space", "split", "desc", "label", "subset", "atlas", "res",
        "den", "hemi", "from", "to", "mode", "stain", "chunk",
        "cohort", "sample", "roi", "tracksys"
    ]
});

/// Check if a string is a valid BIDS entity name
///
/// # Arguments
/// * `entity` - Entity name to validate
///
/// # Returns
/// True if entity is valid BIDS entity name
pub fn is_valid_bids_entity(entity: &str) -> bool {
    VALID_ENTITIES.contains(&entity)
}

/// Canonical name mappings for confound variables
///
/// Maps common alternative names to BIDS-standard names
pub fn get_confound_canonical_mapping(name: &str) -> Option<&'static str> {
    match name.to_lowercase().as_str() {
        "csf" => Some("CSF"),
        "white_matter" | "wm" => Some("WhiteMatter"),
        "global_signal" | "gsr" => Some("GlobalSignal"),
        "std_dvars" => Some("StdDVARS"),
        "framewise_displacement" | "fd" => Some("FramewiseDisplacement"),
        "a_comp_cor" => Some("aCompCor"),
        "t_comp_cor" => Some("tCompCor"),
        "cosine" => Some("Cosine"),
        "motion" => Some("Motion"),
        _ => None,
    }
}

/// Validate mask threshold value
///
/// # Arguments
/// * `threshold` - Threshold value to validate
///
/// # Returns
/// Ok if valid, Error if out of range or invalid
pub fn validate_mask_threshold(threshold: f64) -> crate::Result<()> {
    use crate::BidsError;

    if threshold < 0.0 || threshold > 1.0 {
        return Err(BidsError::InvalidParameter(
            format!("Mask threshold must be between 0.0 and 1.0, got: {}", threshold)
        ));
    }

    if threshold.is_nan() || threshold.is_infinite() {
        return Err(BidsError::InvalidParameter(
            "Mask threshold must be a valid number".to_string()
        ));
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_str_detect_null() {
        assert!(str_detect_null(Some("hello world"), "hello", false));
        assert!(!str_detect_null(Some("hello world"), "goodbye", false));
        assert!(str_detect_null(None, "hello", true));
        assert!(!str_detect_null(None, "hello", false));
    }

    #[test]
    fn test_key_match() {
        assert!(key_match(Some("test"), "test", false));
        assert!(key_match(Some(".*"), "anything", false));
        assert!(key_match(None, "anything", true));
    }

    #[test]
    fn test_bids_path_generation() {
        assert_eq!(
            generate_bids_path("sub-01", Some("ses-01"), "anat", false),
            "sub-01/ses-01/anat"
        );
        assert_eq!(
            generate_bids_path("sub-01", None, "func", true),
            "derivatives/sub-01/func"
        );
    }

    #[test]
    fn test_entity_validation() {
        assert!(is_valid_bids_entity("sub"));
        assert!(is_valid_bids_entity("task"));
        assert!(!is_valid_bids_entity("invalid"));
        assert!(!is_valid_bids_entity("Sub")); // Case sensitive
    }

    #[test]
    fn test_confound_mapping() {
        assert_eq!(get_confound_canonical_mapping("csf"), Some("CSF"));
        assert_eq!(get_confound_canonical_mapping("wm"), Some("WhiteMatter"));
        assert_eq!(get_confound_canonical_mapping("unknown"), None);
    }

    #[test]
    fn test_threshold_validation() {
        assert!(validate_mask_threshold(0.5).is_ok());
        assert!(validate_mask_threshold(0.0).is_ok());
        assert!(validate_mask_threshold(1.0).is_ok());
        assert!(validate_mask_threshold(-0.1).is_err());
        assert!(validate_mask_threshold(1.1).is_err());
        assert!(validate_mask_threshold(f64::NAN).is_err());
    }
}

