use bids_rust::utils::*;
use bids_rust::{BidsError, Result};
use regex::Regex;

// Utility functions that match R bidser functionality
fn str_detect_null(input: Option<&str>, pattern: &str, default: bool) -> bool {
    match input {
        None => default,
        Some(s) => {
            if s.is_empty() {
                default
            } else {
                Regex::new(pattern)
                    .map(|re| re.is_match(s))
                    .unwrap_or(default)
            }
        }
    }
}

fn key_match(pattern: Option<&str>, value: &str, default: bool) -> bool {
    match pattern {
        None => default,
        Some(".*") => true, // Wildcard matches everything
        Some(p) => {
            if p.is_empty() {
                default
            } else {
                Regex::new(p)
                    .map(|re| re.is_match(value))
                    .unwrap_or(false)
            }
        }
    }
}

#[test]
fn test_str_detect_null_basic() {
    // Test with Some values
    assert!(str_detect_null(Some("hello world"), "hello", false));
    assert!(!str_detect_null(Some("hello world"), "goodbye", false));

    // Test with None
    assert!(str_detect_null(None, "hello", true));
    assert!(!str_detect_null(None, "hello", false));

    // Test with empty string
    assert!(str_detect_null(Some(""), "hello", true));
    assert!(!str_detect_null(Some(""), "hello", false));
}

#[test]
fn test_str_detect_null_regex_patterns() {
    // Test regex patterns
    assert!(str_detect_null(Some("sub-01_task-rest_bold.nii.gz"), r"sub-\d+", false));
    assert!(str_detect_null(Some("test123"), r"\d+$", false));
    assert!(!str_detect_null(Some("test"), r"\d+$", false));

    // Test case sensitivity
    assert!(str_detect_null(Some("Hello"), "(?i)hello", false));
    assert!(!str_detect_null(Some("Hello"), "hello", false));
}

#[test]
fn test_key_match_basic() {
    // Test exact matches
    assert!(key_match(Some("test"), "test", false));
    assert!(!key_match(Some("test"), "Test", false));

    // Test wildcard
    assert!(key_match(Some(".*"), "anything", false));
    assert!(key_match(Some(".*"), "", false));

    // Test None pattern
    assert!(key_match(None, "anything", true));
    assert!(!key_match(None, "anything", false));
}

#[test]
fn test_key_match_regex_patterns() {
    // Test regex patterns
    assert!(key_match(Some(r"^task-\w+$"), "task-rest", false));
    assert!(!key_match(Some(r"^task-\w+$"), "task-", false));

    // Test partial matches
    assert!(key_match(Some("rest"), "task-rest", false));
    assert!(key_match(Some("^rest"), "rest-task", false));
    assert!(!key_match(Some("^rest"), "task-rest", false));

    // Test character classes
    assert!(key_match(Some(r"run-\d+"), "run-01", false));
    assert!(!key_match(Some(r"run-\d+"), "run-abc", false));
}

#[test]
fn test_key_match_edge_cases() {
    // Empty pattern
    assert!(key_match(Some(""), "test", true));
    assert!(!key_match(Some(""), "test", false));

    // Invalid regex should return false
    assert!(!key_match(Some("[invalid"), "test", true));

    // Special regex characters
    assert!(key_match(Some(r"file\.txt"), "file.txt", false));
    assert!(!key_match(Some(r"file\.txt"), "filextxt", false));
}

#[test]
fn test_generate_bids_path() {
    // Test raw BIDS path generation
    let path = generate_bids_path("sub-01", Some("ses-01"), "anat", false);
    assert_eq!(path, "sub-01/ses-01/anat");

    let path = generate_bids_path("sub-01", None, "func", false);
    assert_eq!(path, "sub-01/func");

    // Test derivatives path generation
    let path = generate_bids_path("sub-01", Some("ses-01"), "anat", true);
    assert_eq!(path, "derivatives/sub-01/ses-01/anat");
}

#[test]
fn test_reconstruct_node_path() {
    // Test reconstructing paths from tree nodes
    let nodes = vec!["sub-01", "ses-01", "anat"];
    let path = reconstruct_node_path(&nodes, false);
    assert_eq!(path, "sub-01/ses-01/anat");

    // Test with derivatives
    let path = reconstruct_node_path(&nodes, true);
    assert_eq!(path, "derivatives/sub-01/ses-01/anat");

    // Test single node
    let nodes = vec!["dataset_description.json"];
    let path = reconstruct_node_path(&nodes, false);
    assert_eq!(path, "dataset_description.json");
}

// Helper functions for BIDS path operations
fn generate_bids_path(subject: &str, session: Option<&str>, modality: &str, derivatives: bool) -> String {
    let mut path_parts = Vec::new();

    if derivatives {
        path_parts.push("derivatives");
    }

    path_parts.push(subject);

    if let Some(ses) = session {
        path_parts.push(ses);
    }

    path_parts.push(modality);

    path_parts.join("/")
}

fn reconstruct_node_path(nodes: &[&str], derivatives: bool) -> String {
    if derivatives && !nodes.is_empty() {
        let mut path = vec!["derivatives"];
        path.extend_from_slice(nodes);
        path.join("/")
    } else {
        nodes.join("/")
    }
}

#[test]
fn test_null_safe_operations() {
    // Test operations with null/None inputs
    let result: Option<String> = None;
    assert!(!str_detect_null(result.as_deref(), "test", false));
    assert!(str_detect_null(result.as_deref(), "test", true));
}

#[test]
fn test_bids_entity_validation() {
    // Test valid BIDS entities
    let valid_entities = vec!["sub", "ses", "task", "run", "echo", "acq", "ce", "rec", "dir", "space", "desc"];
    for entity in valid_entities {
        assert!(is_valid_bids_entity(entity));
    }

    // Test invalid entities
    assert!(!is_valid_bids_entity("invalid"));
    assert!(!is_valid_bids_entity(""));
    assert!(!is_valid_bids_entity("Sub")); // Case sensitive
}

fn is_valid_bids_entity(entity: &str) -> bool {
    const VALID_ENTITIES: &[&str] = &[
        "sub", "ses", "task", "acq", "ce", "rec", "dir", "run", 
        "mod", "echo", "flip", "inv", "mt", "part", "recording",
        "space", "split", "desc", "label", "subset", "atlas", "res",
        "den", "hemi", "from", "to", "mode"
    ];

    VALID_ENTITIES.contains(&entity)
}

