use bids_rust::{BidsError, BidsProject, Result};
use std::path::PathBuf;
use tempfile::TempDir;

#[cfg(test)]
mod tests {
    use super::*;
    use crate::common::mock_bids::MockBidsBuilder;

    #[test]
    fn test_brain_mask_threshold_validation() {
        // Test valid thresholds
        assert!(validate_mask_threshold(0.0).is_ok());
        assert!(validate_mask_threshold(0.5).is_ok());
        assert!(validate_mask_threshold(1.0).is_ok());

        // Test invalid thresholds
        assert!(validate_mask_threshold(-0.1).is_err());
        assert!(validate_mask_threshold(1.1).is_err());
        assert!(validate_mask_threshold(f64::NAN).is_err());
        assert!(validate_mask_threshold(f64::INFINITY).is_err());
    }

    #[test]
    fn test_create_preproc_mask() -> Result<()> {
        let temp_dir = TempDir::new()?;

        // Create mock BIDS dataset with derivatives
        let mock = MockBidsBuilder::new(&temp_dir)
            .add_participant("sub-01", None)
            .add_file(
                "sub-01",
                None,
                "derivatives/fmriprep/sub-01/anat/sub-01_space-MNI152NLin2009cAsym_desc-brain_mask.nii.gz",
                b"mock mask data"
            )
            .add_file(
                "sub-01",
                None,
                "derivatives/fmriprep/sub-01/anat/sub-01_space-MNI152NLin2009cAsym_desc-preproc_T1w.nii.gz",
                b"mock T1w data"
            )
            .build()?;

        let project = BidsProject::open(&mock)?;

        // Test mask creation with default threshold
        let mask_result = create_brain_mask(&project, "sub-01", None, 0.5);
        assert!(mask_result.is_ok());

        // Test mask creation with custom threshold
        let mask_result = create_brain_mask(&project, "sub-01", None, 0.7);
        assert!(mask_result.is_ok());

        Ok(())
    }

    #[test]
    fn test_find_brain_mask_files() -> Result<()> {
        let temp_dir = TempDir::new()?;

        // Create dataset with multiple mask files
        let mock = MockBidsBuilder::new(&temp_dir)
            .add_participant("sub-01", None)
            .add_participant("sub-02", None)
            .add_file(
                "sub-01",
                None,
                "derivatives/fmriprep/sub-01/anat/sub-01_space-MNI152NLin2009cAsym_desc-brain_mask.nii.gz",
                b"mask1"
            )
            .add_file(
                "sub-01",
                None,
                "derivatives/fmriprep/sub-01/anat/sub-01_space-T1w_desc-brain_mask.nii.gz",
                b"mask2"
            )
            .add_file(
                "sub-02",
                None,
                "derivatives/fmriprep/sub-02/anat/sub-02_space-MNI152NLin2009cAsym_desc-brain_mask.nii.gz",
                b"mask3"
            )
            .build()?;

        let project = BidsProject::open(&mock)?;

        // Test finding masks for specific subject
        let masks = find_brain_masks(&project, Some("sub-01"), None)?;
        assert_eq!(masks.len(), 2);

        // Test finding masks with space filter
        let masks = find_brain_masks(&project, Some("sub-01"), Some("MNI152NLin2009cAsym"))?;
        assert_eq!(masks.len(), 1);

        // Test finding all masks
        let masks = find_brain_masks(&project, None, None)?;
        assert_eq!(masks.len(), 3);

        Ok(())
    }

    #[test]
    fn test_brain_mask_missing_derivatives() -> Result<()> {
        let temp_dir = TempDir::new()?;

        // Create dataset without derivatives
        let mock = MockBidsBuilder::new(&temp_dir)
            .add_participant("sub-01", None)
            .add_file("sub-01", None, "anat/sub-01_T1w.nii.gz", b"T1w data")
            .build()?;

        let project = BidsProject::open(&mock)?;

        // Should return error when no derivatives exist
        let mask_result = create_brain_mask(&project, "sub-01", None, 0.5);
        assert!(mask_result.is_err());

        Ok(())
    }

    #[test]
    fn test_brain_mask_with_sessions() -> Result<()> {
        let temp_dir = TempDir::new()?;

        // Create dataset with sessions
        let mock = MockBidsBuilder::new(&temp_dir)
            .add_participant("sub-01", None)
            .add_file(
                "sub-01",
                Some("ses-01"),
                "derivatives/fmriprep/sub-01/ses-01/anat/sub-01_ses-01_space-MNI152NLin2009cAsym_desc-brain_mask.nii.gz",
                b"ses-01 mask"
            )
            .add_file(
                "sub-01",
                Some("ses-02"),
                "derivatives/fmriprep/sub-01/ses-02/anat/sub-01_ses-02_space-MNI152NLin2009cAsym_desc-brain_mask.nii.gz",
                b"ses-02 mask"
            )
            .build()?;

        let project = BidsProject::open(&mock)?;

        // Test finding masks for specific session
        let masks = find_brain_masks(&project, Some("sub-01"), None)?;
        assert_eq!(masks.len(), 2);

        // Test mask creation with session
        let mask_result = create_brain_mask(&project, "sub-01", Some("ses-01"), 0.5);
        assert!(mask_result.is_ok());

        Ok(())
    }

    // Helper functions for brain mask operations
    fn validate_mask_threshold(threshold: f64) -> Result<()> {
        if threshold < 0.0 || threshold > 1.0 {
            return Err(BidsError::InvalidParameter(
                format!("Mask threshold must be between 0.0 and 1.0, got: {}", threshold)
            ));
        }

        if threshold.is_nan() || threshold.is_infinite() {
            return Err(BidsError::InvalidParameter(
                "Mask threshold must be a valid number".to_string()
            ));
        }

        Ok(())
    }

    fn create_brain_mask(
        project: &BidsProject,
        subject: &str,
        session: Option<&str>,
        threshold: f64,
    ) -> Result<PathBuf> {
        validate_mask_threshold(threshold)?;

        // Look for existing brain mask in derivatives
        let search_result = if let Some(ses) = session {
            project.search_files()
                .subject(subject)
                .session(ses)
                .suffix("mask")
                .desc("brain")
                .extension("nii.gz")
                .find()?
        } else {
            project.search_files()
                .subject(subject)
                .suffix("mask")
                .desc("brain")
                .extension("nii.gz")
                .find()?
        };

        if search_result.is_empty() {
            return Err(BidsError::FileNotFound(
                format!("No brain mask found for subject: {} session: {:?}", subject, session)
            ));
        }

        // In real implementation, would apply threshold to create new mask
        // For tests, just return the found mask path
        Ok(search_result[0].path.clone())
    }

    fn find_brain_masks(
        project: &BidsProject,
        subject: Option<&str>,
        space: Option<&str>,
    ) -> Result<Vec<PathBuf>> {
        let mut search = project.search_files()
            .suffix("mask")
            .desc("brain")
            .extension("nii.gz");

        if let Some(sub) = subject {
            search = search.subject(sub);
        }

        if let Some(sp) = space {
            search = search.space(sp);
        }

        let files = search.find()?;
        Ok(files.into_iter().map(|f| f.path).collect())
    }
}

