use bids_rust::{BidsError, BidsProject, ParsedFilename, Result};
use std::fs;
use std::path::PathBuf;
use tempfile::TempDir;

#[cfg(test)]
mod tests {
    use super::*;
    use crate::common::mock_bids::MockBidsBuilder;

    #[test]
    fn test_null_and_empty_inputs() {
        // Test ParsedFilename with empty string
        let result = ParsedFilename::from_str("");
        assert!(result.is_err());

        // Test with whitespace only
        let result = ParsedFilename::from_str("   ");
        assert!(result.is_err());

        // Test with null-like patterns
        let result = ParsedFilename::from_str("\0");
        assert!(result.is_err());
    }

    #[test]
    fn test_invalid_bids_filenames() {
        let invalid_filenames = vec![
            // Missing subject
            "task-rest_bold.nii.gz",
            // Invalid entity format
            "sub_01_task-rest_bold.nii.gz",
            "sub-01-task-rest_bold.nii.gz",
            // Empty entity values
            "sub-_task-rest_bold.nii.gz",
            "sub-01_task-_bold.nii.gz",
            // Special characters in entity values
            "sub-01@_task-rest_bold.nii.gz",
            "sub-01_task-rest!_bold.nii.gz",
            // Multiple underscores
            "sub-01__task-rest_bold.nii.gz",
            // No suffix
            "sub-01_task-rest.nii.gz",
            // Malformed extensions
            "sub-01_task-rest_bold.nii",
            "sub-01_task-rest_bold.gz",
        ];

        for filename in invalid_filenames {
            let result = ParsedFilename::from_str(filename);
            assert!(result.is_err(), "Should fail to parse: {}", filename);
        }
    }

    #[test]
    fn test_filesystem_permission_errors() -> Result<()> {
        let temp_dir = TempDir::new()?;
        let restricted_dir = temp_dir.path().join("restricted");
        fs::create_dir(&restricted_dir)?;

        // Create a file that we'll make unreadable
        let test_file = restricted_dir.join("dataset_description.json");
        fs::write(&test_file, "{}")?;

        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            let mut perms = fs::metadata(&test_file)?.permissions();
            perms.set_mode(0o000); // No permissions
            fs::set_permissions(&test_file, perms)?;

            // Try to open project with unreadable file
            let result = BidsProject::open(&restricted_dir);
            assert!(result.is_err());

            // Restore permissions for cleanup
            let mut perms = fs::metadata(&test_file)?.permissions();
            perms.set_mode(0o644);
            fs::set_permissions(&test_file, perms)?;
        }

        Ok(())
    }

    #[test]
    fn test_corrupted_json_files() -> Result<()> {
        let temp_dir = TempDir::new()?;

        // Create dataset with corrupted JSON files
        let mock = MockBidsBuilder::new(&temp_dir)
            .add_participant("sub-01", None)
            .build()?;

        // Add corrupted JSON files
        let corrupted_json_cases = vec![
            ("incomplete", r#"{"Name": "Test"#),
            ("invalid_syntax", r#"{"Name": "Test",, "Version": "1.0"}"#),
            ("not_json", "This is not JSON"),
            ("empty", ""),
            ("null_bytes", "{\0\"Name\": \"Test\"}"),
        ];

        for (case_name, content) in corrupted_json_cases {
            let json_path = mock.join(format!("test_{}.json", case_name));
            fs::write(&json_path, content)?;

            // Try to read the corrupted JSON
            let result = read_json_sidecar(&json_path);
            assert!(result.is_err(), "Should fail for case: {}", case_name);
        }

        Ok(())
    }

    #[test]
    fn test_session_boundary_cases() -> Result<()> {
        let temp_dir = TempDir::new()?;

        // Create dataset with edge case session names
        let sessions = vec![
            "ses-01",
            "ses-1",  // Different padding
            "ses-001", // Different padding
            "ses-pre", // Non-numeric
            "ses-post",
            "ses-baseline",
            "ses-1a", // Alphanumeric
            "ses-", // Empty value (invalid)
        ];

        let mut builder = MockBidsBuilder::new(&temp_dir)
            .add_participant("sub-01", None);

        for session in &sessions[..sessions.len()-1] { // Skip the invalid one
            builder = builder.add_file(
                "sub-01",
                Some(session),
                &format!("func/sub-01_{}_task-rest_bold.nii.gz", session),
                b"data"
            );
        }

        let mock = builder.build()?;
        let project = BidsProject::open(&mock)?;

        // Test session enumeration
        let found_sessions = project.sessions()?;
        assert_eq!(found_sessions.len(), sessions.len() - 1); // Minus the invalid one

        // Test regex session filtering
        let numeric_sessions = project.search_files()
            .subject("sub-01")
            .session(r"^\d+$") // Only numeric sessions
            .find()?;

        // Should match ses-01, ses-1, ses-001
        assert!(numeric_sessions.len() >= 3);

        Ok(())
    }

    #[test]
    fn test_run_value_edge_cases() -> Result<()> {
        let temp_dir = TempDir::new()?;

        // Create dataset with various run formats
        let runs = vec![
            ("01", true),
            ("1", true),
            ("001", true),
            ("10", true),
            ("99", true),
            ("0", false), // Invalid - run should start from 1
            ("00", false), // Invalid
            ("-1", false), // Invalid - negative
            ("1a", false), // Invalid - alphanumeric
            ("", false), // Invalid - empty
        ];

