use bids_rust::{BidsError, BidsFile, BidsProject, Result, parse_bids_filename};
use std::collections::HashMap;
use tempfile::TempDir;

mod common;

#[cfg(test)]
mod tests {
    use super::*;
    use crate::common::mock_bids::MockBidsBuilder;

    #[test]
    fn test_fieldmap_parser_basic() {
        // Test basic fieldmap filename parsing
        let filenames = vec![
            "sub-01_ses-01_acq-spinecho_dir-AP_epi.nii.gz",
            "sub-01_ses-01_acq-spinecho_dir-PA_epi.nii.gz",
            "sub-01_magnitude1.nii.gz",
            "sub-01_magnitude2.nii.gz",
            "sub-01_phasediff.nii.gz",
            "sub-01_phase1.nii.gz",
            "sub-01_phase2.nii.gz",
            "sub-01_magnitude.nii.gz",
            "sub-01_fieldmap.nii.gz",
        ];

        for filename in filenames {
            let parsed = parse_fieldmap_filename(filename);
            assert!(parsed.is_ok(), "Failed to parse: {}", filename);

            let result = parsed.unwrap();
            assert_eq!(result.entities.get("sub"), Some(&"01".to_string()));

            // Check for fieldmap-specific entities
            if filename.contains("dir-") {
                assert!(result.entities.contains_key("dir"));
            }
            if filename.contains("magnitude") || filename.contains("phase") || filename.contains("fieldmap") {
                assert!(result.suffix == "magnitude1" || 
                       result.suffix == "magnitude2" || 
                       result.suffix == "magnitude" ||
                       result.suffix == "phasediff" ||
                       result.suffix == "phase1" ||
                       result.suffix == "phase2" ||
                       result.suffix == "fieldmap");
            }
        }
    }

    #[test]
    fn test_fieldmap_types() -> Result<()> {
        let temp_dir = TempDir::new()?;

        // Create dataset with various fieldmap types
        let mock = MockBidsBuilder::new(&temp_dir)
            .add_participant("sub-01", None)
            // Phase difference fieldmap
            .add_file("sub-01", None, "fmap/sub-01_phasediff.nii.gz", b"phasediff")
            .add_file("sub-01", None, "fmap/sub-01_magnitude1.nii.gz", b"mag1")
            .add_file("sub-01", None, "fmap/sub-01_magnitude2.nii.gz", b"mag2")
            // Two phase maps
            .add_file("sub-01", None, "fmap/sub-01_phase1.nii.gz", b"phase1")
            .add_file("sub-01", None, "fmap/sub-01_phase2.nii.gz", b"phase2")
            // Direct fieldmap
            .add_file("sub-01", None, "fmap/sub-01_magnitude.nii.gz", b"magnitude")
            .add_file("sub-01", None, "fmap/sub-01_fieldmap.nii.gz", b"fieldmap")
            // EPI fieldmap
            .add_file("sub-01", None, "fmap/sub-01_dir-AP_epi.nii.gz", b"epi_ap")
            .add_file("sub-01", None, "fmap/sub-01_dir-PA_epi.nii.gz", b"epi_pa")
            .build()?;

        let project = BidsProject::open(&mock)?;

        // Test finding different fieldmap types
        let fmaps = find_fieldmaps(&project, Some("sub-01"), None)?;

        // Should find all fieldmap files
        assert!(fmaps.len() >= 9);

        // Test categorizing fieldmap types
        let categorized = categorize_fieldmaps(&fmaps)?;
        assert!(categorized.contains_key("phasediff"));
        assert!(categorized.contains_key("phase"));
        assert!(categorized.contains_key("direct"));
        assert!(categorized.contains_key("epi"));

        Ok(())
    }

    #[test]
    fn test_fieldmap_intended_for() -> Result<()> {
        let temp_dir = TempDir::new()?;

        // Create dataset with fieldmap and associated JSON
        let json_content = r#"{
            "IntendedFor": ["func/sub-01_task-rest_bold.nii.gz", "func/sub-01_task-motor_bold.nii.gz"],
            "EchoTime1": 0.00456,
            "EchoTime2": 0.00702
        }"#;

        let mock = MockBidsBuilder::new(&temp_dir)
            .add_participant("sub-01", None)
            .add_file("sub-01", None, "fmap/sub-01_phasediff.nii.gz", b"phasediff")
            .add_file("sub-01", None, "fmap/sub-01_phasediff.json", json_content.as_bytes())
            .add_file("sub-01", None, "func/sub-01_task-rest_bold.nii.gz", b"rest")
            .add_file("sub-01", None, "func/sub-01_task-motor_bold.nii.gz", b"motor")
            .build()?;

        let project = BidsProject::open(&mock)?;

        // Test reading IntendedFor metadata
        let fmap_file = project.search_files()
            .subject("sub-01")
            .suffix("phasediff")
            .find()?
            .into_iter()
            .next()
            .ok_or(BidsError::FileNotFound("No fieldmap found".to_string()))?;

        let metadata = read_fieldmap_metadata(&fmap_file)?;
        assert!(metadata.contains_key("IntendedFor"));
        assert!(metadata.contains_key("EchoTime1"));
        assert!(metadata.contains_key("EchoTime2"));

        Ok(())
    }

    #[test]
    fn test_fieldmap_with_sessions() -> Result<()> {
        let temp_dir = TempDir::new()?;

        // Create dataset with sessions
        let mock = MockBidsBuilder::new(&temp_dir)
            .add_participant("sub-01", None)
            .add_file("sub-01", Some("ses-01"), "fmap/sub-01_ses-01_dir-AP_epi.nii.gz", b"ap")
            .add_file("sub-01", Some("ses-01"), "fmap/sub-01_ses-01_dir-PA_epi.nii.gz", b"pa")
            .add_file("sub-01", Some("ses-02"), "fmap/sub-01_ses-02_dir-AP_epi.nii.gz", b"ap")
            .add_file("sub-01", Some("ses-02"), "fmap/sub-01_ses-02_dir-PA_epi.nii.gz", b"pa")
            .build()?;

        let project = BidsProject::open(&mock)?;

        // Test finding fieldmaps for specific session
        let fmaps_ses01 = find_fieldmaps(&project, Some("sub-01"), Some("ses-01"))?;
        assert_eq!(fmaps_ses01.len(), 2);

        let fmaps_ses02 = find_fieldmaps(&project, Some("sub-01"), Some("ses-02"))?;
        assert_eq!(fmaps_ses02.len(), 2);

        Ok(())
    }

    #[test]
    fn test_fieldmap_acq_labels() -> Result<()> {
        let temp_dir = TempDir::new()?;

        // Create dataset with acquisition labels
        let mock = MockBidsBuilder::new(&temp_dir)
            .add_participant("sub-01", None)
            .add_file("sub-01", None, "fmap/sub-01_acq-spinecho_dir-AP_epi.nii.gz", b"se_ap")
            .add_file("sub-01", None, "fmap/sub-01_acq-spinecho_dir-PA_epi.nii.gz", b"se_pa")
            .add_file("sub-01", None, "fmap/sub-01_acq-gre_phasediff.nii.gz", b"gre_pd")
            .add_file("sub-01", None, "fmap/sub-01_acq-gre_magnitude1.nii.gz", b"gre_m1")
            .build()?;

        let project = BidsProject::open(&mock)?;

        // Test finding fieldmaps with specific acquisition
        let se_fmaps = project.search_files()
            .subject("sub-01")
            .modality("fmap")
            .acq("spinecho")
            .find()?;
        assert_eq!(se_fmaps.len(), 2);

        let gre_fmaps = project.search_files()
            .subject("sub-01")
            .modality("fmap")
            .acq("gre")
            .find()?;
        assert_eq!(gre_fmaps.len(), 2);

        Ok(())
    }

    // Helper functions for fieldmap operations
    fn parse_fieldmap_filename(filename: &str) -> Result<ParsedFilename> {
        // This would use the actual BIDS parser with fieldmap-specific rules
        ParsedFilename::from_str(filename)
    }

    fn find_fieldmaps(
        project: &BidsProject,
        subject: Option<&str>,
        session: Option<&str>,
    ) -> Result<Vec<BidsFile>> {
        let mut search = project.search_files().modality("fmap");

        if let Some(sub) = subject {
            search = search.subject(sub);
        }

        if let Some(ses) = session {
            search = search.session(ses);
        }

        search.find()
    }

    fn categorize_fieldmaps(files: &[BidsFile]) -> Result<HashMap<String, Vec<&BidsFile>>> {
        let mut categories: HashMap<String, Vec<&BidsFile>> = HashMap::new();

        for file in files {
            let category = match file.parsed.suffix.as_str() {
                "phasediff" | "magnitude1" | "magnitude2" => "phasediff",
                "phase1" | "phase2" => "phase",
                "magnitude" | "fieldmap" => "direct",
                "epi" => "epi",
                _ => "unknown",
            };

            categories.entry(category.to_string())
                .or_insert_with(Vec::new)
                .push(file);
        }

        Ok(categories)
    }

    fn read_fieldmap_metadata(file: &BidsFile) -> Result<HashMap<String, serde_json::Value>> {
        // This would read the associated JSON sidecar
        let json_path = file.path.with_extension("json");
        if json_path.exists() {
            let content = std::fs::read_to_string(&json_path)?;
            let metadata: HashMap<String, serde_json::Value> = serde_json::from_str(&content)?;
            Ok(metadata)
        } else {
            Ok(HashMap::new())
        }
    }
}

