//! File I/O operations for BIDS data
//!
//! This module provides specialized I/O operations for different types of BIDS files.

pub mod events;
pub mod sidecar;
pub mod confounds;
pub mod builders;

pub use events::{EventsReader, EventData};
pub use sidecar::{SidecarReader, SidecarData};
pub use confounds::{ConfoundsReader, ConfoundsData};
pub use builders::{EventsBuilder, ConfoundsBuilder};

// The traits are defined below, no need to export them here

use crate::error::Result;
use crate::file::BidsFile;

/// Common trait for BIDS file readers
pub trait BidsReader<T> {
    /// Read data from a BIDS file
    fn read(&self, file: &BidsFile) -> Result<T>;

    /// Read data from a file path
    fn read_path(&self, path: &std::path::Path) -> Result<T>;
}

/// Common trait for BIDS file writers
pub trait BidsWriter<T> {
    /// Write data to a BIDS file
    fn write(&self, file: &BidsFile, data: &T) -> Result<()>;

    /// Write data to a file path
    fn write_path(&self, path: &std::path::Path, data: &T) -> Result<()>;
}

/// Utility functions for file I/O
pub mod utils {
    use super::*;
    use std::fs;
    use std::path::Path;

    /// Check if a file exists and is readable
    pub fn is_readable(path: &Path) -> bool {
        path.exists() && path.is_file()
    }

    /// Read file contents as string
    pub fn read_text_file(path: &Path) -> Result<String> {
        fs::read_to_string(path).map_err(Into::into)
    }

    /// Write string to file
    pub fn write_text_file(path: &Path, content: &str) -> Result<()> {
        fs::write(path, content).map_err(Into::into)
    }

    /// Ensure parent directory exists
    pub fn ensure_parent_dir(path: &Path) -> Result<()> {
        if let Some(parent) = path.parent() {
            fs::create_dir_all(parent)?;
        }
        Ok(())
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;
    use std::fs;

    #[test]
    fn test_is_readable() -> Result<()> {
        let temp_dir = TempDir::new()?;
        let file_path = temp_dir.path().join("test.txt");

        // File doesn't exist yet
        assert!(!utils::is_readable(&file_path));

        // Create file
        fs::write(&file_path, "test content")?;
        assert!(utils::is_readable(&file_path));

        Ok(())
    }

    #[test]
    fn test_read_write_text_file() -> Result<()> {
        let temp_dir = TempDir::new()?;
        let file_path = temp_dir.path().join("test.txt");

        let content = "test content";
        utils::write_text_file(&file_path, content)?;

        let read_content = utils::read_text_file(&file_path)?;
        assert_eq!(content, read_content);

        Ok(())
    }

    #[test]
    fn test_ensure_parent_dir() -> Result<()> {
        let temp_dir = TempDir::new()?;
        let nested_file = temp_dir.path().join("nested").join("dir").join("file.txt");

        // Parent directory doesn't exist
        assert!(!nested_file.parent().unwrap().exists());

        // Ensure parent directory
        utils::ensure_parent_dir(&nested_file)?;
        assert!(nested_file.parent().unwrap().exists());

        Ok(())
    }
}

