        let temp_dir = TempDir::new()?;

        // Create confounds with various column patterns
        let confounds = "a_comp_cor_00\ta_comp_cor_01\ta_comp_cor_02\tt_comp_cor_00\tt_comp_cor_01\t\
                        cosine00\tcosine01\tcosine02\ttrans_x\ttrans_y\n\
