                "sub-01",
                None,
                "task-rest",
                Some("01"),
                vec![confounds.to_string()],
            )
            .build()?;

        let project = BidsProject::open(&mock)?;

        // Test pattern matching for component columns
        let result = project.read_confounds()
            .subject("sub-01")
