    }

    #[test]
    fn test_confounds_multi_session() -> Result<()> {
        let temp_dir = TempDir::new()?;

        // Create dataset with multiple sessions
        let confounds_ses1 = "trans_x\ttrans_y\n0.1\t0.2\n0.2\t0.3\n";
