    }

    fn read_confounds_with_validation(
        project: &BidsProject,
        subject: Option<&str>,
        task: Option<&str>,
        run: Option<&str>,
        variables: &[&str],
    ) -> Result<(Vec<ConfoundsData>, Vec<String>)> {
        let mut warnings = Vec::new();

        // In real implementation, would check which variables exist
        // and warn about missing ones
        let mut builder = project.read_confounds();

        if let Some(sub) = subject {
            builder = builder.subject(sub);
        }
        if let Some(t) = task {
            builder = builder.task(t);
        }
        if let Some(r) = run {
            builder = builder.run(r);
        }

        // Check which variables don't exist (mock implementation)
        for var in variables {
            if *var == "GlobalSignal" || *var == "NonExistentVar" {
                warnings.push(var.to_string());
            }
        }

        builder = builder.variables(variables);
        let data = builder.read()?;

        Ok((data, warnings))
    }

    fn read_confounds_nested(
        project: &BidsProject,
        subject: Option<&str>,
        task: Option<&str>,
        run: Option<&str>,
        variables: &[&str],
    ) -> Result<Vec<HashMap<String, serde_json::Value>>> {
        let mut builder = project.read_confounds();

        if let Some(sub) = subject {
            builder = builder.subject(sub);
        }
        if let Some(t) = task {
            builder = builder.task(t);
        }
        if let Some(r) = run {
            builder = builder.run(r);
        }

        builder = builder.variables(variables).nest(true);
        let data = builder.read()?;

        // Convert to nested format for testing
        let nested: Vec<HashMap<String, serde_json::Value>> = data.iter()
            .map(|conf| {
                let mut map = HashMap::new();
                map.insert(".subid".to_string(), serde_json::Value::String(conf.subject.clone()));
                map.insert(".task".to_string(), serde_json::Value::String(conf.task.clone()));
                map.insert(".run".to_string(), serde_json::Value::String(conf.run.as_ref().unwrap_or(&"".to_string()).clone()));
                map.insert("data".to_string(), serde_json::to_value(&conf.data).unwrap());
                map
            })
            .collect();

        Ok(nested)
    }

    fn read_confounds_flat(
        project: &BidsProject,
        subject: Option<&str>,
        task: Option<&str>,
