        flat.insert(".task".to_string(), vec![1.0; data.len()]);
        flat.insert(".run".to_string(), vec![1.0; data.len()]);

        // Add data columns (simplified for testing)
        for var in variables {
            flat.insert(var.to_string(), vec![0.1, 0.2, 0.3, 0.4]);
        }

        Ok(flat)
    }

