//! Confound file reading and processing
//!
//! This module provides functionality for reading BIDS confound files (.tsv format)
//! and processing confound variables, including PCA-based dimensionality reduction.

use std::collections::HashMap;
use std::path::Path;
use csv::ReaderBuilder;
use serde::{Deserialize, Serialize};

use crate::error::{BidsError, Result};
use crate::file::BidsFile;
use crate::io::utils;
use crate::analysis::pca::{PcaProcessor, PcaResult, pca_confounds};
use super::BidsReader;

/// Confound data structure
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct ConfoundsData {
    /// Confound variables (variable_name -> values)
    pub variables: HashMap<String, Vec<f64>>,
    /// String variables (for non-numeric columns)
    pub string_variables: HashMap<String, Vec<String>>,
    /// Variable names in order
    pub variable_names: Vec<String>,
    /// Number of time points
    pub n_timepoints: usize,
    /// File path where this data was loaded from
    #[serde(skip)]
    pub path: std::path::PathBuf,
    /// Subject ID
    pub subject: String,
    /// Session ID (optional)
    pub session: Option<String>,
    /// Task name (optional)
    pub task: Option<String>,
    /// Run ID (optional)
    pub run: Option<String>,
    /// PCA results (if computed)
    #[serde(skip)]
    pub pca_result: Option<crate::analysis::pca::PcaResult>,
}

/// Confound file reader
pub struct ConfoundsReader {
    /// Column delimiter (default: tab)
    delimiter: u8,
    /// Include string variables
    include_string_vars: bool,
    /// Filter for specific confound types
    confound_filter: Option<Vec<String>>,
    /// Handle missing values
    handle_missing: bool,
    /// Missing value replacement strategy
    missing_strategy: MissingStrategy,
}

/// Strategy for handling missing values
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum MissingStrategy {
    /// Replace with zero
    Zero,
    /// Replace with mean of the column
    Mean,
    /// Replace with median of the column
    Median,
    /// Remove rows with missing values
    Remove,
    /// Keep as NaN (will cause errors in PCA)
    Keep,
}

impl ConfoundsReader {
    /// Create a new confounds reader
    pub fn new() -> Self {
        Self {
            delimiter: b'\t',
            include_string_vars: false,
            confound_filter: None,
            handle_missing: true,
            missing_strategy: MissingStrategy::Mean,
        }
    }

    /// Set the column delimiter
    pub fn delimiter(mut self, delimiter: u8) -> Self {
        self.delimiter = delimiter;
        self
    }

    /// Set whether to include string variables
    pub fn include_string_vars(mut self, include: bool) -> Self {
        self.include_string_vars = include;
        self
    }

    /// Set confound filter (only include variables matching these patterns)
    pub fn confound_filter(mut self, filter: Vec<String>) -> Self {
        self.confound_filter = Some(filter);
        self
    }

    /// Set missing value handling strategy
    pub fn missing_strategy(mut self, strategy: MissingStrategy) -> Self {
        self.missing_strategy = strategy;
        self.handle_missing = true;
        self
    }

    /// Filter for motion confounds only
    pub fn motion_only(mut self) -> Self {
        self.confound_filter = Some(vec![
            "trans_x".to_string(),
            "trans_y".to_string(),
            "trans_z".to_string(),
            "rot_x".to_string(),
            "rot_y".to_string(),
            "rot_z".to_string(),
        ]);
        self
    }

    /// Filter for tissue confounds only
    pub fn tissue_only(mut self) -> Self {
        self.confound_filter = Some(vec![
            "csf".to_string(),
            "white_matter".to_string(),
            "global_signal".to_string(),
        ]);
        self
    }

    /// Filter for common fMRIPrep confounds
    pub fn fmriprep_common(mut self) -> Self {
        self.confound_filter = Some(vec![
            "trans_x".to_string(),
            "trans_y".to_string(),
            "trans_z".to_string(),
            "rot_x".to_string(),
            "rot_y".to_string(),
            "rot_z".to_string(),
            "csf".to_string(),
            "white_matter".to_string(),
            "global_signal".to_string(),
            "framewise_displacement".to_string(),
            "dvars".to_string(),
        ]);
        self
    }

    /// Read confounds from a CSV reader
    fn read_from_reader<R: std::io::Read>(&self, reader: R) -> Result<ConfoundsData> {
        let mut csv_reader = ReaderBuilder::new()
            .delimiter(self.delimiter)
            .has_headers(true)
            .from_reader(reader);

        let headers = csv_reader.headers()?.clone();
        let mut variables = HashMap::new();
        let mut string_variables = HashMap::new();
        let mut variable_names = Vec::new();

        // Initialize storage for each column
        for header in headers.iter() {
            if let Some(ref filter) = self.confound_filter {
                if !filter.iter().any(|pattern| header.to_lowercase().contains(&pattern.to_lowercase())) {
                    continue;
                }
            }

            variables.insert(header.to_string(), Vec::new());
            if self.include_string_vars {
                string_variables.insert(header.to_string(), Vec::new());
            }
            variable_names.push(header.to_string());
        }

        let mut n_timepoints = 0;

        // Read records
        for result in csv_reader.records() {
            let record = result?;
            n_timepoints += 1;

            for (i, header) in headers.iter().enumerate() {
                if !variable_names.contains(&header.to_string()) {
                    continue;
                }

                if let Some(value_str) = record.get(i) {
                    // Try to parse as number
                    if let Ok(value) = value_str.parse::<f64>() {
                        if let Some(var_data) = variables.get_mut(header) {
                            var_data.push(value);
                        }
                    } else if value_str.is_empty() || value_str.to_lowercase() == "n/a" || value_str.to_lowercase() == "nan" {
                        // Handle missing values
                        if let Some(var_data) = variables.get_mut(header) {
                            var_data.push(f64::NAN);
                        }
                    } else {
                        // String value
                        if let Some(var_data) = variables.get_mut(header) {
                            var_data.push(f64::NAN);
                        }
                        if self.include_string_vars {
                            if let Some(str_data) = string_variables.get_mut(header) {
                                str_data.push(value_str.to_string());
                            }
                        }
                    }
                }
            }
        }

        // Handle missing values
        if self.handle_missing {
            for (var_name, var_data) in variables.iter_mut() {
                self.handle_missing_values(var_name, var_data)?;
            }
        }

        Ok(ConfoundsData {
            variables,
            string_variables,
            variable_names,
            n_timepoints,
            path: std::path::PathBuf::new(),
            subject: String::new(),
            session: None,
            task: None,
            run: None,
            pca_result: None,
        })
    }

    /// Handle missing values in a variable
    fn handle_missing_values(&self, var_name: &str, data: &mut Vec<f64>) -> Result<()> {
        let nan_indices: Vec<usize> = data.iter()
            .enumerate()
            .filter(|(_, &value)| value.is_nan())
            .map(|(i, _)| i)
            .collect();

        if nan_indices.is_empty() {
            return Ok(());
        }

        match self.missing_strategy {
            MissingStrategy::Zero => {
                for &idx in &nan_indices {
                    data[idx] = 0.0;
                }
            }
            MissingStrategy::Mean => {
                let valid_values: Vec<f64> = data.iter()
                    .filter(|&&x| !x.is_nan())
                    .copied()
                    .collect();

                if valid_values.is_empty() {
                    return Err(BidsError::parse_error(
                        "confounds.tsv",
                        &format!("Variable '{}' has no valid values", var_name),
                    ));
                }

                let mean = valid_values.iter().sum::<f64>() / valid_values.len() as f64;
                for &idx in &nan_indices {
                    data[idx] = mean;
                }
            }
            MissingStrategy::Median => {
                let mut valid_values: Vec<f64> = data.iter()
                    .filter(|&&x| !x.is_nan())
                    .copied()
                    .collect();

                if valid_values.is_empty() {
                    return Err(BidsError::parse_error(
                        "confounds.tsv",
                        &format!("Variable '{}' has no valid values", var_name),
                    ));
                }

                valid_values.sort_by(|a, b| a.partial_cmp(b).unwrap());
                let median = if valid_values.len() % 2 == 0 {
                    (valid_values[valid_values.len() / 2 - 1] + valid_values[valid_values.len() / 2]) / 2.0
                } else {
                    valid_values[valid_values.len() / 2]
                };

                for &idx in &nan_indices {
                    data[idx] = median;
                }
            }
            MissingStrategy::Remove => {
                // This is more complex and would require removing entire rows
                // For now, just replace with zero
                for &idx in &nan_indices {
                    data[idx] = 0.0;
                }
            }
            MissingStrategy::Keep => {
                // Do nothing - keep NaN values
            }
        }

        Ok(())
    }
}

impl Default for ConfoundsReader {
    fn default() -> Self {
        Self::new()
    }
}

impl BidsReader<ConfoundsData> for ConfoundsReader {
    fn read(&self, file: &BidsFile) -> Result<ConfoundsData> {
        if !file.is_confounds() {
            return Err(BidsError::validation_error(
                "File is not a confounds file",
                Some("suffix".to_string()),
            ));
        }

        self.read_path(&file.path)
    }

    fn read_path(&self, path: &Path) -> Result<ConfoundsData> {
        if !utils::is_readable(path) {
            return Err(BidsError::file_not_found(path));
        }

        let file = std::fs::File::open(path)?;
        self.read_from_reader(file)
    }
}

impl ConfoundsData {
    /// Create a new empty ConfoundsData
    pub fn new() -> Self {
        Self {
            variables: HashMap::new(),
            string_variables: HashMap::new(),
            variable_names: Vec::new(),
            n_timepoints: 0,
            path: std::path::PathBuf::new(),
            subject: String::new(),
            session: None,
            task: None,
            run: None,
            pca_result: None,
        }
    }

    /// Get the number of variables
    pub fn n_variables(&self) -> usize {
        self.variables.len()
    }

    /// Get the number of timepoints
    pub fn n_timepoints(&self) -> usize {
        self.n_timepoints
    }

    /// Check if the confounds data is empty
    pub fn is_empty(&self) -> bool {
        self.variables.is_empty()
    }

    /// Get variable names
    pub fn variable_names(&self) -> &[String] {
        &self.variable_names
    }

    /// Get a specific variable
    pub fn get_variable(&self, name: &str) -> Option<&Vec<f64>> {
        self.variables.get(name)
    }

    /// Get variable data as a HashMap (for PCA)
    pub fn as_hashmap(&self) -> HashMap<String, Vec<f64>> {
        self.variables.clone()
    }

    /// Filter variables by pattern
    pub fn filter_variables(&self, patterns: &[String]) -> Self {
        let mut filtered_variables = HashMap::new();
        let mut filtered_string_variables = HashMap::new();
        let mut filtered_names = Vec::new();

        for var_name in &self.variable_names {
            if patterns.iter().any(|pattern| var_name.to_lowercase().contains(&pattern.to_lowercase())) {
                if let Some(data) = self.variables.get(var_name) {
                    filtered_variables.insert(var_name.clone(), data.clone());
                    filtered_names.push(var_name.clone());
                }
                if let Some(str_data) = self.string_variables.get(var_name) {
                    filtered_string_variables.insert(var_name.clone(), str_data.clone());
                }
            }
        }

        Self {
            variables: filtered_variables,
            string_variables: filtered_string_variables,
            variable_names: filtered_names,
            n_timepoints: self.n_timepoints,
            path: self.path.clone(),
            subject: self.subject.clone(),
            session: self.session.clone(),
            task: self.task.clone(),
            run: self.run.clone(),
            pca_result: None,
        }
    }

    /// Get motion confounds (6 motion parameters)
    pub fn motion_confounds(&self) -> Self {
        self.filter_variables(&[
            "trans_x".to_string(),
            "trans_y".to_string(),
            "trans_z".to_string(),
            "rot_x".to_string(),
            "rot_y".to_string(),
            "rot_z".to_string(),
        ])
    }

    /// Get tissue confounds
    pub fn tissue_confounds(&self) -> Self {
        self.filter_variables(&[
            "csf".to_string(),
            "white_matter".to_string(),
            "global_signal".to_string(),
        ])
    }

    /// Perform PCA on confound variables
    pub fn pca(&self, n_components: Option<usize>) -> Result<PcaResult> {
        if self.variables.is_empty() {
            return Err(BidsError::analysis_error("No confound variables available for PCA", None));
        }

        pca_confounds(self.as_hashmap(), n_components, None)
    }

    /// Perform PCA with variance threshold
    pub fn pca_variance_threshold(&self, threshold: f64) -> Result<PcaResult> {
        if self.variables.is_empty() {
            return Err(BidsError::analysis_error("No confound variables available for PCA", None));
        }

        pca_confounds(self.as_hashmap(), None, Some(threshold))
    }

    /// Get PCA processor for more advanced operations
    pub fn pca_processor(&self) -> Result<PcaProcessor> {
        if self.variables.is_empty() {
            return Err(BidsError::analysis_error("No confound variables available for PCA", None));
        }

        PcaProcessor::from_confound_map(self.as_hashmap())
    }

    /// Get summary statistics
    pub fn summary(&self) -> ConfoundsSummary {
        let mut variable_stats = HashMap::new();

        for (var_name, data) in &self.variables {
            let valid_data: Vec<f64> = data.iter().filter(|&&x| !x.is_nan()).copied().collect();

            if !valid_data.is_empty() {
                let mean = valid_data.iter().sum::<f64>() / valid_data.len() as f64;
                let variance = valid_data.iter().map(|x| (x - mean).powi(2)).sum::<f64>() / (valid_data.len() - 1) as f64;
                let std_dev = variance.sqrt();
                let min = valid_data.iter().fold(f64::INFINITY, |a, &b| a.min(b));
                let max = valid_data.iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b));

                variable_stats.insert(var_name.clone(), VariableStats {
                    mean,
                    std_dev,
                    min,
                    max,
                    n_valid: valid_data.len(),
                    n_missing: data.len() - valid_data.len(),
                });
            }
        }

        ConfoundsSummary {
            n_variables: self.n_variables(),
            n_timepoints: self.n_timepoints,
            variable_names: self.variable_names.clone(),
            variable_stats,
        }
    }

    /// Check if a column exists
    pub fn has_column(&self, column_name: &str) -> bool {
        // First check direct column name
        if self.variables.contains_key(column_name) {
            return true;
        }

        // Then check canonical mappings
        let canonical = match column_name {
            "motion" => {
                // Check if any motion parameter exists
                return self.variables.keys().any(|k| {
                    k.starts_with("trans_") || k.starts_with("rot_")
                });
            }
            "csf" => "csf",
            "wm" | "white_matter" => "white_matter",
            "gm" | "gray_matter" | "grey_matter" => "gray_matter",
            "global_signal" => "global_signal",
            _ => column_name,
        };

        self.variables.contains_key(canonical)
    }

    /// Select specific columns
    pub fn select_columns(&self, columns: &[String]) -> Result<Self> {
        let mut selected_vars = HashMap::new();
        let mut selected_names = Vec::new();

        for col in columns {
            // Handle canonical names
            match col.as_str() {
                "motion" => {
                    // Add all motion parameters
                    for (name, data) in &self.variables {
                        if name.starts_with("trans_") || name.starts_with("rot_") {
                            selected_vars.insert(name.clone(), data.clone());
                            if !selected_names.contains(name) {
                                selected_names.push(name.clone());
                            }
                        }
                    }
                }
                "csf" => {
                    if let Some(data) = self.variables.get("csf") {
                        selected_vars.insert("csf".to_string(), data.clone());
                        selected_names.push("csf".to_string());
                    } else if let Some(data) = self.variables.get("CSF") {
                        selected_vars.insert("CSF".to_string(), data.clone());
                        selected_names.push("CSF".to_string());
                    }
                }
                "wm" | "white_matter" => {
                    if let Some(data) = self.variables.get("white_matter") {
                        selected_vars.insert("white_matter".to_string(), data.clone());
                        selected_names.push("white_matter".to_string());
                    } else if let Some(data) = self.variables.get("WhiteMatter") {
                        selected_vars.insert("WhiteMatter".to_string(), data.clone());
                        selected_names.push("WhiteMatter".to_string());
                    }
                }
                _ => {
                    // Direct column name
                    if let Some(data) = self.variables.get(col) {
                        selected_vars.insert(col.clone(), data.clone());
                        selected_names.push(col.clone());
                    }
                }
            }
        }

        if selected_vars.is_empty() {
            return Err(BidsError::validation_error(
                "No matching columns found",
                Some(columns.join(", ")),
            ));
        }

        Ok(Self {
            variables: selected_vars,
            string_variables: HashMap::new(),
            variable_names: selected_names,
            n_timepoints: self.n_timepoints,
            path: self.path.clone(),
            subject: self.subject.clone(),
            session: self.session.clone(),
            task: self.task.clone(),
            run: self.run.clone(),
            pca_result: None,
        })
    }

    /// Convert to matrix for PCA
    pub fn to_matrix(&self) -> Result<nalgebra::DMatrix<f64>> {
        if self.variables.is_empty() {
            return Err(BidsError::validation_error(
                "No numeric variables available for matrix conversion",
                None,
            ));
        }

        let n_rows = self.n_timepoints;
        let n_cols = self.variables.len();
        let mut data = Vec::with_capacity(n_rows * n_cols);

        // Fill data column by column (column-major order for nalgebra)
        for var_name in &self.variable_names {
            if let Some(var_data) = self.variables.get(var_name) {
                data.extend_from_slice(var_data);
            }
        }

        Ok(nalgebra::DMatrix::from_vec(n_rows, n_cols, data))
    }
}

impl Default for ConfoundsData {
    fn default() -> Self {
        Self::new()
    }
}

/// Summary statistics for a single variable
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct VariableStats {
    /// Mean value
    pub mean: f64,
    /// Standard deviation
    pub std_dev: f64,
    /// Minimum value
    pub min: f64,
    /// Maximum value
    pub max: f64,
    /// Number of valid (non-missing) values
    pub n_valid: usize,
    /// Number of missing values
    pub n_missing: usize,
}

/// Summary statistics for confounds data
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ConfoundsSummary {
    /// Number of variables
    pub n_variables: usize,
    /// Number of timepoints
    pub n_timepoints: usize,
    /// Variable names
    pub variable_names: Vec<String>,
    /// Per-variable statistics
    pub variable_stats: HashMap<String, VariableStats>,
}

impl std::fmt::Display for ConfoundsSummary {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        writeln!(f, "Confounds Summary")?;
        writeln!(f, "Variables: {}", self.n_variables)?;
        writeln!(f, "Timepoints: {}", self.n_timepoints)?;
        writeln!(f, "\nVariable Statistics:")?;

        for var_name in &self.variable_names {
            if let Some(stats) = self.variable_stats.get(var_name) {
                writeln!(f, "  {}: mean={:.3}, std={:.3}, range=[{:.3}, {:.3}], valid={}, missing={}", 
                         var_name, stats.mean, stats.std_dev, stats.min, stats.max, 
                         stats.n_valid, stats.n_missing)?;
            }
        }

        Ok(())
    }
}

/// Convenience function to read confounds from a path
pub fn read_confounds<P: AsRef<Path>>(path: P) -> Result<ConfoundsData> {
    let reader = ConfoundsReader::new();
    reader.read_path(path.as_ref())
}

/// Convenience function to read confounds with motion filter
pub fn read_motion_confounds<P: AsRef<Path>>(path: P) -> Result<ConfoundsData> {
    let reader = ConfoundsReader::new().motion_only();
    reader.read_path(path.as_ref())
}

/// Convenience function to read confounds with tissue filter
pub fn read_tissue_confounds<P: AsRef<Path>>(path: P) -> Result<ConfoundsData> {
    let reader = ConfoundsReader::new().tissue_only();
    reader.read_path(path.as_ref())
}

/// Convenience function to read fMRIPrep confounds
pub fn read_fmriprep_confounds<P: AsRef<Path>>(path: P) -> Result<ConfoundsData> {
    let reader = ConfoundsReader::new().fmriprep_common();
    reader.read_path(path.as_ref())
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;
    use std::fs;

    fn create_test_confounds_file() -> Result<(TempDir, std::path::PathBuf)> {
        let temp_dir = TempDir::new()?;
        let file_path = temp_dir.path().join("sub-01_task-test_desc-confounds_regressors.tsv");

        let content = "trans_x\ttrans_y\ttrans_z\trot_x\trot_y\trot_z\tcsf\twhite_matter\tglobal_signal\tframewise_displacement\n\
                       0.1\t0.2\t0.3\t0.01\t0.02\t0.03\t100.0\t200.0\t1000.0\t0.5\n\
                       0.2\t0.3\t0.4\t0.02\t0.03\t0.04\t101.0\t201.0\t1001.0\t0.6\n\
                       0.3\t0.4\t0.5\t0.03\t0.04\t0.05\t102.0\t202.0\t1002.0\t0.7\n\
                       0.4\t0.5\t0.6\t0.04\t0.05\t0.06\t103.0\t203.0\t1003.0\t0.8\n";

        fs::write(&file_path, content)?;
        Ok((temp_dir, file_path))
    }

    fn create_test_confounds_with_missing() -> Result<(TempDir, std::path::PathBuf)> {
        let temp_dir = TempDir::new()?;
        let file_path = temp_dir.path().join("confounds_missing.tsv");

        let content = "trans_x\ttrans_y\tcsf\n\
                       0.1\t0.2\t100.0\n\
                       0.2\tn/a\t101.0\n\
                       0.3\t0.4\t\n\
                       0.4\t0.5\t103.0\n";

        fs::write(&file_path, content)?;
        Ok((temp_dir, file_path))
    }

    #[test]
    fn test_read_confounds_file() -> Result<()> {
        let (_temp_dir, file_path) = create_test_confounds_file()?;

        let confounds = read_confounds(&file_path)?;

        assert_eq!(confounds.n_variables(), 10);
        assert_eq!(confounds.n_timepoints(), 4);

        let trans_x = confounds.get_variable("trans_x").unwrap();
        assert_eq!(trans_x, &vec![0.1, 0.2, 0.3, 0.4]);

        let csf = confounds.get_variable("csf").unwrap();
        assert_eq!(csf, &vec![100.0, 101.0, 102.0, 103.0]);

        Ok(())
    }

    #[test]
    fn test_confounds_reader_filters() -> Result<()> {
        let (_temp_dir, file_path) = create_test_confounds_file()?;

        // Test motion filter
        let motion_reader = ConfoundsReader::new().motion_only();
        let motion_confounds = motion_reader.read_path(&file_path)?;
        assert_eq!(motion_confounds.n_variables(), 6);
        assert!(motion_confounds.get_variable("trans_x").is_some());
        assert!(motion_confounds.get_variable("csf").is_none());

        // Test tissue filter
        let tissue_reader = ConfoundsReader::new().tissue_only();
        let tissue_confounds = tissue_reader.read_path(&file_path)?;
        assert_eq!(tissue_confounds.n_variables(), 3);
        assert!(tissue_confounds.get_variable("csf").is_some());
        assert!(tissue_confounds.get_variable("trans_x").is_none());

        Ok(())
    }

    #[test]
    fn test_confounds_filtering() -> Result<()> {
        let (_temp_dir, file_path) = create_test_confounds_file()?;
        let confounds = read_confounds(&file_path)?;

        // Test motion confounds filter
        let motion = confounds.motion_confounds();
        assert_eq!(motion.n_variables(), 6);
        assert!(motion.get_variable("trans_x").is_some());

        // Test tissue confounds filter
        let tissue = confounds.tissue_confounds();
        assert_eq!(tissue.n_variables(), 3);
        assert!(tissue.get_variable("csf").is_some());

        Ok(())
    }

    #[test]
    fn test_confounds_pca() -> Result<()> {
        let (_temp_dir, file_path) = create_test_confounds_file()?;
        let confounds = read_confounds(&file_path)?;

        // Test PCA with specified components
        let pca_result = confounds.pca(Some(3))?;
        assert_eq!(pca_result.n_components(), 3);
        assert_eq!(pca_result.n_observations(), 4);

        // Test PCA with variance threshold
        let pca_result = confounds.pca_variance_threshold(0.95)?;
        assert!(pca_result.cumulative_variance_ratio.last().unwrap() >= &0.95);

        Ok(())
    }

    #[test]
    fn test_missing_value_handling() -> Result<()> {
        let (_temp_dir, file_path) = create_test_confounds_with_missing()?;

        // Test mean imputation
        let reader = ConfoundsReader::new().missing_strategy(MissingStrategy::Mean);
        let confounds = reader.read_path(&file_path)?;

        let trans_y = confounds.get_variable("trans_y").unwrap();
        // Should have replaced n/a with mean of valid values
        assert!(!trans_y.iter().any(|&x| x.is_nan()));

        Ok(())
    }

    #[test]
    fn test_confounds_summary() -> Result<()> {
        let (_temp_dir, file_path) = create_test_confounds_file()?;
        let confounds = read_confounds(&file_path)?;

        let summary = confounds.summary();
        assert_eq!(summary.n_variables, 10);
        assert_eq!(summary.n_timepoints, 4);

        let trans_x_stats = summary.variable_stats.get("trans_x").unwrap();
        assert_eq!(trans_x_stats.mean, 0.25);
        assert_eq!(trans_x_stats.n_valid, 4);
        assert_eq!(trans_x_stats.n_missing, 0);

        Ok(())
    }

    #[test]
    fn test_convenience_functions() -> Result<()> {
        let (_temp_dir, file_path) = create_test_confounds_file()?;

        // Test motion confounds
        let motion_confounds = read_motion_confounds(&file_path)?;
        assert_eq!(motion_confounds.n_variables(), 6);

        // Test tissue confounds
        let tissue_confounds = read_tissue_confounds(&file_path)?;
        assert_eq!(tissue_confounds.n_variables(), 3);

        // Test fMRIPrep confounds
        let fmriprep_confounds = read_fmriprep_confounds(&file_path)?;
        assert_eq!(fmriprep_confounds.n_variables(), 10);

        Ok(())
    }

    #[test]
    fn test_confounds_data_methods() -> Result<()> {
        let (_temp_dir, file_path) = create_test_confounds_file()?;
        let confounds = read_confounds(&file_path)?;

        assert!(!confounds.is_empty());
        assert_eq!(confounds.variable_names().len(), 10);

        let as_hashmap = confounds.as_hashmap();
        assert_eq!(as_hashmap.len(), 10);
        assert!(as_hashmap.contains_key("trans_x"));

        Ok(())
    }
}

